    local lastHurtCount     = pb.lastHurtCount                  --上次挑战造成伤害（-1表示今日未挑战）
    local buffCount         = pb.buffCount                      --当前鼓舞层数
    local hurtRankName      = pb.hurtRankName                   --伤害排行榜玩家名字
    local hurtRankCount     = pb.hurtRankCount                  --伤害排行榜玩家伤害
    local extraCount        = pb.extraCount                     --额外加成挑战次数（免费）
    local level             = pb.level                          --关卡等级
    local scoreLevel        = pb.scoreLevel                     --关卡评分等级
    local buffNum           = pb.buffNum                        --剩余鼓舞次数
    local doubleState       = pb.doubleState                    --下次挑战是否双倍
    local difficult         = pb.difficult                      --关卡难度
    local scoreWord         = pb.scoreWord                      --关卡积分词条， 用|分割
    local endTime           = pb.endTime                        --boss结束时间 时间戳
    local selfRank          = pb.selfRank                       --伤害排名 -1标识没有排名
    local scoreWordNext     = pb.scoreWordNext                  --下一个boss的加成词条
    local lastCallTime      = pb.lastCallTime                   --上次召集时间

    local info = {
        braveId         = braveId,
        currentHp       = tonumber(currentHp),
        battleCount     = battleCount,
        battleBuyCount  = battleBuyCount,
        lastHurtCount   = tonumber(lastHurtCount),
        buffCount       = buffCount,
        hurtRankName    = hurtRankName,
        hurtRankCount   = tonumber(hurtRankCount),
        extraCount      = extraCount,
        level           = level,
        scoreLevel      = scoreLevel,
        buffNum         = buffNum,
        doubleState     = doubleState,
        difficult       = difficult,
        scoreWord       = scoreWord,
        endTime         = endTime,
        selfRank        = selfRank,
        scoreWordNext   = scoreWordNext,
        lastCallTime    = lastCallTime,
    }
    self._guildBrave = info
end
