function ModelGuildBoss:OnGuildCallMemberResp(pb)
    local lastBuffTime = pb.lastBuffTime            --集结CD结束时间（处于CD中返回该时间飘字用）
    if not string.isempty(lastBuffTime) and tonumber(lastBuffTime)/1000 > 0 then
        local systime = GetTimestamp()
        local timespan = tonumber(lastBuffTime)/1000 - systime
        local h=math.floor(timespan/3600)
        local m=math.floor(timespan/60)%60
        local s=math.floor(timespan)%60
        local timeStr = string.format("%02d:%02d:%02d", h,m,s)
        GF.ShowMessage(string.replace(ccClientText(14128),timeStr))
    else
        self._guildBrave.lastCallTime = GetTimestamp() * 1000
        GF.ShowMessage(ccClientText(32744))
    end
end
