function ModelGuildBoss:GetNewGuildDungeonRankRefByRating(rating,level)
    local list = self._ratingRankList or {}
    local subList = list[rating]
    if subList then
        return subList
    end
    local lv = level or 1
    local unlockRewardLevel = self:GetNewGuildDungeonConfigRefByKey("unlockRewardLevel")
    subList = {}
    for i, v in pairs(GameTable.ClanDungeonRankRef) do
        if v.rating  == rating then
            local data = {
                refId = v.refId,
                sort = v.sort,
                rank = v.rank,
                reward = v.reward,
            }
            if lv >= unlockRewardLevel then
                local reward = string.format("%s,%s",v.reward,v.extraReward)
                data.reward = reward
            end
            table.insert(subList,data)
        end
    end
    if #subList > 1 then
        table.sort(subList,function (a,b)
            return a.refId < b.refId
        end)
    end
    list[rating] = subList
    self._ratingRankList = list
    return subList
end
function ModelGuildBoss:GetNewGuildDungeonIntegralRewardRefByRating(rating)
    local list = self._ratingIntegralRewardList or {}
    local subList = list[rating]
    if subList then
        return subList
    end
    subList = {}
    for i, v in pairs(GameTable.ClanDungeonIntegralRewardRef) do
        if v.rating  == rating then
            table.insert(subList,v)
        end
    end
    if #subList > 1 then
        table.sort(subList,function (a,b)
            return a.refId < b.refId
        end)
    end
    list[rating] = subList
    self._ratingIntegralRewardList = list
    return subList
end
