function ModelGuildBoss:GetGuildBuyNumNeed(num)--公会副本挑战次数购买需求----第一次需求|第二次需要|第三次需要|第四次需要…
    local braveInfo = self:GetGuildBraveInfo()
    num =  num and braveInfo.battleBuyCount + num or braveInfo.battleBuyCount + 1
    local needStr = self:GetNewGuildDungeonConfigRefByKey("GuildBuyTimeNeed")
    local attrArry = string.split(needStr,"|")
    if num > #attrArry then
        num = #attrArry
    end
    local itemStr = attrArry[num]
    local item = LxDataHelper.ParseItem_3(itemStr)
    return item
end
function ModelGuildBoss:OnClickSweep()--点击扫荡
    if not self:CanSweep(true) then
        return
    end

    local braveInfo = self:GetGuildBraveInfo()
    if not braveInfo then
        return
    end
    --local currentHp = braveInfo.currentHp
    --if tonumber(currentHp) <= 0 then
    --    GF.ShowMessage(ccClientText(14148))
    --    return
    --end

    local lastHurtCount = braveInfo.lastHurtCount
    local battleCount = braveInfo.battleCount             --今日已挑战次数
    local battleBuyCount = braveInfo.battleBuyCount       --今日已购买次数
    local extraCount = braveInfo.extraCount               --额外加成挑战次数（免费）
    local challengeNum = gModelGuild:GetVipBraveAddNum(1) --免费挑战次数
    local residueNum = challengeNum + battleBuyCount + extraCount
    if battleCount - residueNum >= 0 then
        if braveInfo.currentHp > 0 then
            self:SetGuyNumPop(3)
        else
            self:SetGuyNumPop(4)
        end
        return true
    end
    local braveId = braveInfo.braveId
    --if  braveInfo.currentHp > 0 then
    lastHurtCount = LUtil.PowerNumberCoversion(lastHurtCount)

    local count = challengeNum - braveInfo.battleCount + braveInfo.battleBuyCount + braveInfo.extraCount
    if count > 0 then
        GF.OpenWnd("UIOrdinTip", {
            refId = 100011,
            para = { lastHurtCount },
            func = function(...)
                gModelGuildBoss:OnGuildBraveSweepReq(braveId)
            end
        })
    else
        local item = self:GetGuildBuyNumNeed()
        GF.OpenWnd("UIOrdinTip", {
                refId = 100012,
                para = { item.itemNum, lastHurtCount, gModelGuild:GetVipBraveAddNum(2) - battleBuyCount },
                func = function(...)
                    self:OnGuildBraveSweepReq(braveId)
                end
        })
    end


    --end

end
function ModelGuildBoss:CanSweep(showTip)
    local braveInfo = self:GetGuildBraveInfo()
    if not braveInfo then
        return
    end

    local lastHurtCount = braveInfo.lastHurtCount
    if not lastHurtCount or lastHurtCount <= 0 then
        if showTip then
            GF.ShowMessage(ccClientText(32737))
        end
        return
    end

    return true
end

function ModelGuildBoss:GetLastHurtCnt()
    local braveInfo = self:GetGuildBraveInfo()
    if not braveInfo then
        return 0
    end

    local lastHurtCount = braveInfo.lastHurtCount
    return lastHurtCount or 0
end

function ModelGuildBoss:SetGuyNumPop(type)--设置购买弹窗		1-挑战，2-【+】，3-扫荡
    local braveInfo = self:GetGuildBraveInfo()
    local battleBuyCount = braveInfo.battleBuyCount
    local guyNum = gModelGuild:GetVipBraveAddNum(2)
    if battleBuyCount >= guyNum then
        if type ~= 2 then
            GF.ShowMessage(ccClientText(14119))
        else
            GF.ShowMessage(ccClientText(14129))
        end
        return
    end
    local item = self:GetGuildBuyNumNeed()
    local itemId   = item.itemId
    local itemName = gModelItem:GetNameByRefId(itemId)
    local itemNum  = item.itemNum
    local needStr = itemNum
    local refId = 100010
    local para = {}
    local consume
    if type == 1 then
        refId=100009
        needStr = itemNum
        para = {needStr,guyNum - battleBuyCount}
    elseif type == 2 then
        refId = 100010
        para = {needStr,guyNum - battleBuyCount}
    elseif type==3 then
        refId = 100012
        local lastHurtCount = LUtil.PowerNumberCoversion(braveInfo.lastHurtCount)
        para = {needStr,lastHurtCount,guyNum - battleBuyCount}
        consume = {itemNum, itemId}
    elseif type == 4 then
        refId = 100022
        needStr = itemNum
        para = {needStr,guyNum - battleBuyCount}
    end
    GF.OpenWnd("UIOrdinTip",{refId=refId,para=para,func=function (...)
        local num = gModelItem:GetNumByRefId(itemId)
        if num < item.itemNum then
            gModelGeneral:OpenGetWayWnd({itemId = itemId})
            return
        end
        --购买协议
        self:OnGuildBuyReq(type)
    end, consume = {itemNum,itemId} })
end
function ModelGuildBoss:GetBraveBossMonsterRefId()
    local info = self:GetGuildBraveInfo()
    local levelRef = self:GetNewGuildDungeonLevelRefByRefId(info.level)
    return levelRef.monster
end
--获取当前公会boss排行奖励表
function ModelGuildBoss:GetNewGuildDungeonRankRef()
    local list = {}
    local info = self:GetGuildBraveInfo()
    local levelRef = gModelGuildBoss:GetNewGuildDungeonLevelRefByRefId(info.level)
    local level = levelRef.level
    local rating = info.scoreLevel
    local lv = level or 1
    local unlockRewardLevel = self:GetNewGuildDungeonConfigRefByKey("unlockRewardLevel")

    for i, v in pairs(GameTable.ClanDungeonRankRef) do
        if v.rating  == rating then
            local data = {
                refId = v.refId,
                sort = v.sort,
                rank = v.rank,
                reward = v.reward,
            }
            if lv >= unlockRewardLevel then
                local reward = string.format("%s,%s",v.reward,v.extraReward)
                data.reward = reward
            end
            table.insert(list,data)
        end
    end
    table.sort(list , function (a,b)
        if(a.sort ~= b.sort)then
            return a.sort < b.sort
        end
        return false
    end)
    return list
end
function ModelGuildBoss:GetGuildBraveBattlePrepareLv()
    local info = self:GetGuildBraveInfo()
    local levelRef = self:GetNewGuildDungeonLevelRefByRefId(info.level)
    local level = levelRef.level
    return level
end
